<template><main class="page"><section class="hero"><p class="kicker">Market Orca</p><h1>Watchlist Insights</h1><p>Top risk, momentum, catalyst, suggested action.</p></section><section v-if="data?.count===0" class="panel"><h2>Belum ada watchlist</h2><p>Tambah asset favorit dulu dari homepage Market Orca.</p></section><section v-if="data" class="cards"><article v-for="i in data.items" :key="i.slug" class="card"><div class="top"><b>{{i.symbol}}</b><span :class="i.risk">{{i.risk}}</span></div><h2>{{i.name}}</h2><strong :class="i.change_percent>=0?'up':'down'">{{i.change_percent}}%</strong><p>{{i.action}}</p><small v-if="i.catalyst">{{i.catalyst.source}} · {{i.catalyst.title}}</small></article></section></main></template><script setup>import{ref,onMounted}from'vue';import{apiGet}from'../lib/api';const data=ref(null);onMounted(async()=>{data.value=await apiGet('/api/watchlist/insights')})</script><style scoped>.page{max-width:1100px;margin:auto;padding:24px 14px 70px;color:var(--ink)}.hero,.panel,.card{background:var(--bg2);border:2px solid var(--line-strong);box-shadow:5px 5px 0 var(--line-strong);padding:18px;margin-bottom:16px}.hero{background:#facc15}.hero h1{font-size:clamp(42px,8vw,80px);margin:0;letter-spacing:-.07em}.kicker{text-transform:uppercase;font-weight:900;color:#9a3412}.cards{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:16px}.top{display:flex;justify-content:space-between}.top b{font-size:24px}.high{color:var(--red)}.medium{color:var(--accent2)}.low{color:var(--green)}.up{color:var(--green);font-size:36px}.down{color:var(--red);font-size:36px}.card p{font-weight:900}.card small{color:var(--muted)}</style>